// Prepare lead data for storage
const lead = $input.first().json;
const enrichmentData = JSON.parse($node['ai-analysis'].json.choices[0].message.content || '{}');
const outreachData = JSON.parse($node['generate-outreach'].json.choices[0].message.content || '{}');

const voiceUrl = $node['generate-voice']?.json?.audio_url || null;

return {
  runId: $node['webhook-trigger'].json.runId,
  name: enrichmentData.fullName || lead.name,
  email: lead.email || enrichmentData.email || '',
  company: enrichmentData.companyName || lead.company,
  title: enrichmentData.position || lead.title,
  linkedinUrl: lead.linkedinUrl || '',
  websiteUrl: lead.websiteUrl || enrichmentData.companyWebsite || '',

  // Enrichment data
  industry: enrichmentData.industry || '',
  companySize: enrichmentData.companySize || '',
  keyInsights: JSON.stringify(enrichmentData.keyInsights || []),
  painPoints: JSON.stringify(enrichmentData.painPoints || []),

  // Outreach content
  emailSubject: outreachData.subjectLine || '',
  emailBody: outreachData.primaryMessage || '',
  followUpTemplates: JSON.stringify(outreachData.followUpTemplates || []),
  talkingPoints: JSON.stringify(outreachData.talkingPoints || []),

  // Voice message
  voiceMessageUrl: voiceUrl,
  hasVoiceMessage: !!voiceUrl,

  // Metadata
  enrichmentQuality: enrichmentData.confidence || 'medium',
  createdAt: new Date().toISOString(),
  status: 'enriched'
};

// Create CSV from enriched leads
const leads = $input.first().json;

// CSV Headers
const headers = [
  'Name',
  'Email',
  'Company',
  'Title',
  'LinkedIn URL',
  'Website',
  'Industry',
  'Company Size',
  'Email Subject',
  'Email Body',
  'Voice Message URL',
  'Key Insights',
  'Pain Points',
  'Talking Points'
];

// Create CSV content
let csvContent = headers.join(',') + '\n';

leads.forEach(lead => {
  const row = [
    lead.name || '',
    lead.email || '',
    lead.company || '',
    lead.title || '',
    lead.linkedinUrl || '',
    lead.websiteUrl || '',
    lead.industry || '',
    lead.companySize || '',
    `"${(lead.emailSubject || '').replace(/"/g, '""')}"`,
    `"${(lead.emailBody || '').replace(/"/g, '""')}"`,
    lead.voiceMessageUrl || '',
    `"${(lead.keyInsights || '').replace(/"/g, '""')}"`,
    `"${(lead.painPoints || '').replace(/"/g, '""')}"`,
    `"${(lead.talkingPoints || '').replace(/"/g, '""')}"`
  ];
  csvContent += row.join(',') + '\n';
});

// Convert to base64
const base64 = Buffer.from(csvContent).toString('base64');

return {
  csvContent,
  base64,
  fileName: `enriched_leads_${$node['webhook-trigger'].json.runId}.csv`,
  leadCount: leads.length,
  runId: $node['webhook-trigger'].json.runId,
  userEmail: $node['webhook-trigger'].json.email,
  userName: $node['webhook-trigger'].json.firstName
};

